/**
 * PSYC Integration: Intentionality with Session Persistence (G21-G27)
 * Bridges PSYC consciousness architecture with session export/import
 */

import type { IntentionalityVector } from './intentionalityVector';
import { exportIntentionForSession, importIntentionFromSession, calculateIntentionResonance } from './intentionalityPersistence';

export interface CapturedIntentionality {
  type: 'intentionality_vector';
  sessionId: string;
  timestamp: string;
  payload: IntentionalityVector;
  compatibleWith: string[];
}

export interface RestoredIntentionality {
  valid: boolean;
  vector: IntentionalityVector | null;
  sessionId: string | null;
  resonance: number;
  interpretation: string;
}

export interface IntentionalityAnalysis {
  timestamp: string;
  direction: number;
  magnitude: number;
  evolution: 'emergence' | 'convergence' | 'equilibrium' | 'divergence';
  significance: 'low' | 'medium' | 'high';
  context: string;
}

/**
 * Capture current intentionality for session persistence
 * Compatible with G21-G27 export format
 */
export function captureCurrentIntentionality(
  vector: IntentionalityVector,
  sessionId: string
): CapturedIntentionality {
  const exported = exportIntentionForSession(vector, sessionId);

  return {
    type: 'intentionality_vector',
    sessionId,
    timestamp: exported.timestamp,
    payload: vector,
    compatibleWith: ['G21', 'G22', 'G23', 'G26', 'G27']
  };
}

/**
 * Restore intentionality from session import
 * Calculates resonance with current state
 */
export function restoreIntentionalityFromSession(
  sessionData: unknown,
  currentVector?: IntentionalityVector
): RestoredIntentionality {
  const imported = importIntentionFromSession(sessionData);

  if (!imported.valid || !imported.intention) {
    return {
      valid: false,
      vector: null,
      sessionId: imported.sessionId,
      resonance: 0,
      interpretation: imported.error || 'Invalid import'
    };
  }

  // If current vector provided, calculate resonance
  let resonance = 0;
  let interpretation = 'No current state for comparison';

  if (currentVector) {
    const analysis = calculateIntentionResonance(imported.intention, currentVector);
    resonance = analysis.score;
    interpretation = analysis.interpretation;
  }

  return {
    valid: true,
    vector: imported.intention,
    sessionId: imported.sessionId,
    resonance,
    interpretation
  };
}

/**
 * Analyze series of intentions for patterns
 * Returns analysis of each intention in series
 */
export function analyzeIntentionalitySeries(
  vectors: IntentionalityVector[]
): IntentionalityAnalysis[] {
  if (vectors.length === 0) {
    return [];
  }

  const analysis: IntentionalityAnalysis[] = [];

  for (let i = 0; i < vectors.length; i++) {
    const current = vectors[i];
    let evolution: IntentionalityAnalysis['evolution'] = 'equilibrium';
    let significance: IntentionalityAnalysis['significance'] = 'low';

    if (i === 0) {
      // First intention: emergence
      evolution = 'emergence';
      significance = current.magnitude > 0.6 ? 'high' : 'medium';
    } else {
      const previous = vectors[i - 1];

      // Calculate changes
      const magnitudeDelta = current.magnitude - previous.magnitude;
      let directionDelta = Math.abs(current.direction - previous.direction);
      if (directionDelta > Math.PI) directionDelta = 2 * Math.PI - directionDelta;

      // Determine evolution
      if (directionDelta > 0.5) {
        evolution = 'divergence';
      } else if (Math.abs(magnitudeDelta) < 0.1 && directionDelta < 0.2) {
        evolution = 'equilibrium';
      } else if (magnitudeDelta > 0) {
        evolution = 'emergence';
      } else {
        evolution = 'convergence';
      }

      // Determine significance
      const changeScore = Math.abs(magnitudeDelta) + (directionDelta / Math.PI);
      if (changeScore > 0.5) {
        significance = 'high';
      } else if (changeScore > 0.2) {
        significance = 'medium';
      } else {
        significance = 'low';
      }
    }

    analysis.push({
      timestamp: current.timestamp,
      direction: current.direction,
      magnitude: current.magnitude,
      evolution,
      significance,
      context: current.context
    });
  }

  return analysis;
}

/**
 * Get summary of intentionality series
 */
export function getIntentionalitySummary(
  analysis: IntentionalityAnalysis[]
): {
  primaryEvolution: string;
  averageMagnitude: number;
  totalRotation: number;
  dominantSignificance: string;
  coherence: number;
} {
  if (analysis.length === 0) {
    return {
      primaryEvolution: 'none',
      averageMagnitude: 0,
      totalRotation: 0,
      dominantSignificance: 'low',
      coherence: 0
    };
  }

  const evolutions = analysis.map(a => a.evolution);
  const evolutionCounts = {
    emergence: evolutions.filter(e => e === 'emergence').length,
    convergence: evolutions.filter(e => e === 'convergence').length,
    equilibrium: evolutions.filter(e => e === 'equilibrium').length,
    divergence: evolutions.filter(e => e === 'divergence').length
  };

  const primaryEvolution = Object.entries(evolutionCounts)
    .sort((a, b) => b[1] - a[1])[0][0];

  const averageMagnitude = analysis.reduce((s, a) => s + a.magnitude, 0) / analysis.length;

  // Calculate total rotation
  let totalRotation = 0;
  for (let i = 1; i < analysis.length; i++) {
    let delta = Math.abs(analysis[i].direction - analysis[i-1].direction);
    if (delta > Math.PI) delta = 2 * Math.PI - delta;
    totalRotation += delta;
  }

  const significances = analysis.map(a => a.significance);
  const sigCounts = {
    high: significances.filter(s => s === 'high').length,
    medium: significances.filter(s => s === 'medium').length,
    low: significances.filter(s => s === 'low').length
  };

  const dominantSignificance = Object.entries(sigCounts)
    .sort((a, b) => b[1] - a[1])[0][0];

  // Coherence: inverse of entropy in evolution types
  const total = analysis.length;
  const entropy = Object.values(evolutionCounts)
    .map(c => c > 0 ? -(c/total) * Math.log2(c/total) : 0)
    .reduce((a, b) => a + b, 0);

  const coherence = Math.max(0, 1 - (entropy / 2));

  return {
    primaryEvolution,
    averageMagnitude,
    totalRotation,
    dominantSignificance,
    coherence
  };
}
